"use strict";(globalThis.webpackChunkmythogen_engine_blog=globalThis.webpackChunkmythogen_engine_blog||[]).push([[9991],{8776(e,t,n){n.r(t),n.d(t,{assets:()=>l,contentTitle:()=>s,default:()=>u,frontMatter:()=>i,metadata:()=>r,toc:()=>h});var o=n(4848),a=n(8453);const i={title:"Not a Transformation, But a Contraction: Another Way to Read the AI Job Wave",sidebar_position:20260409},s="Not a Transformation, But a Contraction: Another Way to Read the AI Job Wave",r={id:"TechNotes/20260409AIJobWave",title:"Not a Transformation, But a Contraction: Another Way to Read the AI Job Wave",description:"This year, there are two distinct narratives circulating in the market regarding AI and software engineering jobs.",source:"@site/i18n/en/docusaurus-plugin-content-docs/current/TechNotes/20260409AIJobWave.md",sourceDirName:"TechNotes",slug:"/TechNotes/20260409AIJobWave",permalink:"/MythogenEngine/en/docs/TechNotes/20260409AIJobWave",draft:!1,unlisted:!1,tags:[],version:"current",sidebarPosition:20260409,frontMatter:{title:"Not a Transformation, But a Contraction: Another Way to Read the AI Job Wave",sidebar_position:20260409},sidebar:"docs",previous:{title:'Did Jensen Huang Say "Liberal Arts Students Won"? You Got Fooled by the Clickbait.',permalink:"/MythogenEngine/en/docs/TechNotes/NvidaAllInPodcast"},next:{title:'When everyone is still learning how to "raise lobsters", AI Platforms are learning how to "replace lobsters".',permalink:"/MythogenEngine/en/docs/TechNotes/CLAW"}},l={},h=[{value:"How Anxiety is Priced",id:"how-anxiety-is-priced",level:2},{value:"What&#39;s Really Happening: Simultaneous Imbalance of Supply and Demand",id:"whats-really-happening-simultaneous-imbalance-of-supply-and-demand",level:2},{value:"&quot;Shortage of Engineers&quot; and &quot;Layoff Waves&quot; Are Not Actually Contradictory",id:"shortage-of-engineers-and-layoff-waves-are-not-actually-contradictory",level:2},{value:"This Isn&#39;t the First Time",id:"this-isnt-the-first-time",level:2},{value:"So, What Should We Do?",id:"so-what-should-we-do",level:2},{value:"Conclusion",id:"conclusion",level:2}];function d(e){const t={blockquote:"blockquote",em:"em",h1:"h1",h2:"h2",header:"header",img:"img",li:"li",ol:"ol",p:"p",strong:"strong",ul:"ul",...(0,a.R)(),...e.components};return(0,o.jsxs)(o.Fragment,{children:[(0,o.jsx)(t.header,{children:(0,o.jsx)(t.h1,{id:"not-a-transformation-but-a-contraction-another-way-to-read-the-ai-job-wave",children:"Not a Transformation, But a Contraction: Another Way to Read the AI Job Wave"})}),"\n",(0,o.jsxs)(t.p,{children:[(0,o.jsx)(t.img,{src:n(1281).A+"",width:"2816",height:"1536"}),"\nThis year, there are two distinct narratives circulating in the market regarding AI and software engineering jobs."]}),"\n",(0,o.jsx)(t.p,{children:"On one side, people are talking about layoff waves, recent graduates struggling to find jobs, and a Stanford study indicating that employment for young people in highly AI-exposed professions is down by 14%. On the other side, we hear about record-high job openings, companies fighting for talent, and how \"transforming\" your skills will present new opportunities. When you string these two together, it\u2019s easy to reach a convenient conclusion: \"The market is weeding people out. As long as you upgrade from a 'coder' to an 'engineer', you'll be safe.\""}),"\n",(0,o.jsx)(t.p,{children:"This narrative is very easy to sell. In fact, it is being sold aggressively right now."}),"\n",(0,o.jsx)(t.p,{children:'Open Facebook, LinkedIn, or YouTube, and you\'ll see a whole flock of people talking in almost the exact same sentence pattern: "The coder era is over," "Engineers who know AI can double their salaries," "If you don\'t get on board right now, it will be too late." Their posts look similar, their conclusions look similar, and even their stock photos look similar. And usually, at the very bottom of the article, you\'ll find a link to a course, a portal to a community, or a consultation form.'}),"\n",(0,o.jsx)(t.p,{children:"This is not a coincidence; it's a business. And what this business is selling isn't skills, it's an antidote to anxiety."}),"\n",(0,o.jsx)(t.h2,{id:"how-anxiety-is-priced",children:"How Anxiety is Priced"}),"\n",(0,o.jsxs)(t.p,{children:["To get people to pay for a cure, you first have to make them believe they are sick. Therefore, the first step of this narrative is ",(0,o.jsx)(t.em,{children:"always"})," to translate a structural problem into a personal one."]}),"\n",(0,o.jsxs)(t.ul,{children:["\n",(0,o.jsx)(t.li,{children:'It\u2019s not "the entire industry requires fewer people," but "you are not strong enough."'}),"\n",(0,o.jsx)(t.li,{children:'It\u2019s not "the pyramid is narrowing," but "you are standing on the wrong side."'}),"\n",(0,o.jsx)(t.li,{children:'It\u2019s not "demand hasn\'t grown," but "you haven\'t kept up."'}),"\n"]}),"\n",(0,o.jsx)(t.p,{children:'This translation step is crucial because structural problems can\'t be resolved by selling courses\u2014you can\'t sell a course on "Fixing the Entire Industry\'s Supply and Demand." But personal problems can be sold, and they can be sold repeatedly. An individual can always "upgrade a little more," "learn another new tool," or "buy the next class."'}),"\n",(0,o.jsx)(t.p,{children:"The second step is to manufacture an exit that sounds reasonable. The \"Coder vs. Engineer\" framing is so popular not because it's the most accurate, but because it's the easiest to sell. It implies a clear path: you are here now, and if you just do A, B, and C, you will get there. It packages a future without guarantees into a train ticket you can purchase."}),"\n",(0,o.jsxs)(t.p,{children:["The third step is to create an artificial rush so you don't have time to think. All narratives of this type feature immense time pressure: if you don\u2019t learn it now, it will be too late; the window is closing; in six months, you won't be able to catch up. Because once you have a moment to calm down and do the math, you will realize a very simple truth: if the top-tier positions are really ",(0,o.jsx)(t.em,{children:"that"})," short of talent and the pay is really ",(0,o.jsx)(t.em,{children:"that"})," great, why aren't these people taking those engineering jobs instead of spending their time writing Facebook posts to sell you courses?"]}),"\n",(0,o.jsx)(t.p,{children:"I\u2019m not saying everyone selling AI courses is running a scam; some are genuinely teaching valuable things. What I am saying is that when you see an entire horde of people shouting with the exact same phrases, the exact same anxiety, and the exact same cure, you should ask yourself first: Are they describing reality, or are they describing a version of reality that makes it convenient for them to do business?"}),"\n",(0,o.jsx)(t.h2,{id:"whats-really-happening-simultaneous-imbalance-of-supply-and-demand",children:"What's Really Happening: Simultaneous Imbalance of Supply and Demand"}),"\n",(0,o.jsx)(t.p,{children:"After peeling off the layer of sales rhetoric, let's look back at the data."}),"\n",(0,o.jsx)(t.p,{children:'The most direct impact AI has had on the software industry isn\'t "the required skills have changed," but rather "the same output now takes fewer people." Previously, a feature might have taken five engineers two months to build; now, two people plus AI can finish it in one month. This isn\'t science fiction; it is happening right now.'}),"\n",(0,o.jsx)(t.p,{children:"The core issue was never here. The problem is that when productivity triples, the market demand for software does not miraculously triple with it."}),"\n",(0,o.jsx)(t.p,{children:"Corporate IT budgets haven't skyrocketed. The SaaS market was saturated ages ago. Startup funding environments have contracted. On the consumer side, no new use cases have emerged capable of absorbing all this excess capacity. Over the past fifteen years, we've already coasted off the \"smartphones for everyone\" dividend, and so far, AI has yet to spawn a new demand driver of equivalent magnitude."}),"\n",(0,o.jsx)(t.p,{children:"And so, a very simple truth arises\u2014one that most people are reluctant to talk about:"}),"\n",(0,o.jsxs)(t.blockquote,{children:["\n",(0,o.jsx)(t.p,{children:(0,o.jsx)(t.strong,{children:"Efficiency has increased, but the newly generated capacity cannot find an outlet."})}),"\n"]}),"\n",(0,o.jsx)(t.p,{children:"This is the true root cause of the layoff wave. It's not that engineers aren't good enough, or that workers aren't trying hard enough. It's the simple fact that the overall number of people this industry needs is decreasing."}),"\n",(0,o.jsx)(t.h2,{id:"shortage-of-engineers-and-layoff-waves-are-not-actually-contradictory",children:'"Shortage of Engineers" and "Layoff Waves" Are Not Actually Contradictory'}),"\n",(0,o.jsx)(t.p,{children:"Once you understand this, the seemingly contradictory phenomena are resolved."}),"\n",(0,o.jsxs)(t.p,{children:["Companies ",(0,o.jsx)(t.em,{children:"are"})," indeed clamoring for talent, but they are fighting over a tiny group at the very top of the pyramid\u2014those who can design complex systems, integrate AI workflows, and take direct responsibility for business results. These people were rare to begin with, and they've become even rarer now that a single person is expected to output what previously took a whole team. Accordingly, the number of open positions for them is breaking records, and their compensation will continue to rise."]}),"\n",(0,o.jsx)(t.p,{children:"But the middle and the bottom of the pyramid are vanishing. The previous structure\u2014where a project needed one architect, three seniors, ten mid-levels, and a bunch of juniors\u2014is being compressed down to one architect plus two or three seniors who know how to use AI. Mid-levels are becoming dispensable, and juniors are finding almost no entry points."}),"\n",(0,o.jsx)(t.p,{children:'So, "record job openings" and "young people can\'t find jobs" are merely two sides of the same coin: the top is hunting aggressively for talent, the bottom is collapsing, and the middle is being hollowed out.'}),"\n",(0,o.jsxs)(t.p,{children:["This is not a ",(0,o.jsx)(t.em,{children:"transformation"}),", it is a ",(0,o.jsx)(t.em,{children:"contraction"}),". Transformation implies that old positions disappear while new ones emerge, allowing people to migrate over. Contraction means old positions disappear, and the number of new positions is vastly smaller than the old ones, leaving the majority of people with nowhere to go."]}),"\n",(0,o.jsx)(t.h2,{id:"this-isnt-the-first-time",children:"This Isn't the First Time"}),"\n",(0,o.jsx)(t.p,{children:"If this pattern sounds familiar, it's because it truly is. The textile workers of the 19th century, the agricultural labor force in the mid-20th century, the factory line workers in the latest wave of automation\u2014every leap in productivity is interspersed with a \"period of surplus.\" Productivity races ahead while demand slowly catches up. And that gap in between? That's your unemployment wave."}),"\n",(0,o.jsx)(t.p,{children:'Eventually, new demands will appear, and new forms of jobs will grow out of it. But the word "eventually" is dangerous. Because before "eventually" arrives, there are usually ten or twenty years of burden placed squarely on the shoulders of the generation caught in the middle. History books won\'t remember their names; they\'ll only remember that "the economy successfully transformed later on."'}),"\n",(0,o.jsx)(t.p,{children:"Right now, we are very likely that generation."}),"\n",(0,o.jsx)(t.h2,{id:"so-what-should-we-do",children:"So, What Should We Do?"}),"\n",(0,o.jsx)(t.p,{children:"I am not going to tell you to \"quickly go learn AI and upgrade yourself to an engineer.\" Not because learning AI is useless, but because that phrase masquerades a structural issue as a personal failing that can be solved just with hard work. If the entire industry needs fewer people, no matter how many people take classes, someone will still be squeezed out\u2014and they won't be squeezed out because they're stupid, they\u2019ll be squeezed out because there simply aren't enough seats."}),"\n",(0,o.jsx)(t.p,{children:"A more honest way of putting it is this:"}),"\n",(0,o.jsxs)(t.ol,{children:["\n",(0,o.jsxs)(t.li,{children:[(0,o.jsx)(t.strong,{children:"Accept that the next few years will be ugly."})," It\u2019s not that you aren't good enough; the era is adjusting the number of people it needs, and you just happen to be standing at the tail end of that adjustment. Think this through clearly first, so all your future decisions aren't built on a foundation of misdirected self-doubt."]}),"\n",(0,o.jsxs)(t.li,{children:[(0,o.jsx)(t.strong,{children:"Reduce reliance on a single source of income."}),' Not because having a "side hustle" is trendy, but because when an industry is contracting, betting all your chips on a single job carries dramatically higher risks than before. One extra income source equates to one extra layer of buffer.']}),"\n",(0,o.jsxs)(t.li,{children:[(0,o.jsx)(t.strong,{children:"Bring down your fixed expenses."})," The defining characteristic of a surplus period is that income becomes unstable and unpredictable. What will keep you afloat isn't how much you earn, but how slowly you burn through it."]}),"\n",(0,o.jsxs)(t.li,{children:[(0,o.jsx)(t.strong,{children:"Accumulate transferable, cross-domain capabilities, rather than a single technical skill."})," Purely technical tasks are the easiest for AI to swallow. What's genuinely hard to replace is judgment, domain knowledge, the ability to deal with people, and the capacity to stitch disparate parts into a functional system. These aren't things you can fast-track at a bootcamp, but in the long run, they are worth far more than writing a thousand lines of code."]}),"\n",(0,o.jsxs)(t.li,{children:[(0,o.jsx)(t.strong,{children:'Re-evaluate what "work" actually means in your life.'})," If jobs can no longer steadily provide identity, income, and meaning the way they used to, where else are you going to get those things? This is a massive question, but the sooner you start thinking about it, the better, because this isn't a transition that will resolve in a year or two."]}),"\n"]}),"\n",(0,o.jsx)(t.h2,{id:"conclusion",children:"Conclusion"}),"\n",(0,o.jsx)(t.p,{children:'Those who tell you "everything will be fine if you upgrade" usually have something to sell you. Those who tell you "the world is going to collapse" are usually selling something else. Neither side is truly describing what you are currently experiencing.'}),"\n",(0,o.jsx)(t.p,{children:"What you are experiencing is a surplus period where a technological leap is outpacing demand growth. It won't last forever, but it will last for a while, and it's not going to be a comfortable ride."}),"\n",(0,o.jsx)(t.p,{children:"Seeing this clearly isn't an invitation to despair; it's a way to ensure your energy is spent in the right places\u2014spent on figuring out how to survive, rather than wallowing in self-doubt, and certainly not on buying the next non-existent train ticket."})]})}function u(e={}){const{wrapper:t}={...(0,a.R)(),...e.components};return t?(0,o.jsx)(t,{...e,children:(0,o.jsx)(d,{...e})}):d(e)}},1281(e,t,n){n.d(t,{A:()=>o});const o=n.p+"assets/images/Gemini_Generated_Image_3h2kd43h2kd43h2k-f23541d49f821851680a50a97af8e202.png"},8453(e,t,n){n.d(t,{R:()=>s,x:()=>r});var o=n(6540);const a={},i=o.createContext(a);function s(e){const t=o.useContext(i);return o.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:s(e.components),o.createElement(i.Provider,{value:t},e.children)}}}]);